DELETE FROM leave_balances WHERE employee_id IN (SELECT id FROM employees WHERE employee_code LIKE 'EMP-%' OR employee_code LIKE 'TEST-%');
DELETE FROM leave_requests WHERE employee_id IN (SELECT id FROM employees WHERE employee_code LIKE 'EMP-%' OR employee_code LIKE 'TEST-%');
DELETE FROM payroll WHERE employee_id IN (SELECT id FROM employees WHERE employee_code LIKE 'EMP-%' OR employee_code LIKE 'TEST-%');
DELETE FROM attendance WHERE employee_id IN (SELECT id FROM employees WHERE employee_code LIKE 'EMP-%' OR employee_code LIKE 'TEST-%');
DELETE FROM work_records WHERE employee_id IN (SELECT id FROM employees WHERE employee_code LIKE 'EMP-%' OR employee_code LIKE 'TEST-%');
DELETE FROM quality_issues WHERE reported_by IN (SELECT id FROM employees WHERE employee_code LIKE 'EMP-%' OR employee_code LIKE 'TEST-%');
DELETE FROM quality_issues WHERE resolved_by IN (SELECT id FROM employees WHERE employee_code LIKE 'EMP-%' OR employee_code LIKE 'TEST-%');
DELETE FROM production_logs WHERE supervisor_id IN (SELECT id FROM employees WHERE employee_code LIKE 'EMP-%' OR employee_code LIKE 'TEST-%');
DELETE FROM caps_employee_map WHERE employee_id IN (SELECT id FROM employees WHERE employee_code LIKE 'EMP-%' OR employee_code LIKE 'TEST-%');
DELETE FROM employees WHERE employee_code LIKE 'EMP-%' OR employee_code LIKE 'TEST-%';

